    std::string line;
    std::string result;
    int current_line = 1;

    // Read lines before the target line
    while (current_line < line_number - 5 && std::getline(file, line)) {
        current_line++;
    }

    // Collect 5 lines before
    for (int i = 0; i < 5 && std::getline(file, line); ++i) {
        result += std::to_string(current_line) + ": " + line + "\n";
        current_line++;
    }

    // Collect the target line and 5 after
    for (int i = 0; i <= 5 && std::getline(file, line); ++i) {
        result += std::to_string(current_line) + ": " + line + "\n";
        current_line++;
    }

    file.close();
    return result;
} 

